// Preparar dados para publicação
const input = $input.first().json;

// Montar caption com hashtags
let caption = input.metadata?.captions || input.metadata?.title || '';
const hashtags = input.metadata?.hashtags || '';
if (hashtags) {
  caption = caption.trim() + '\n\n' + hashtags.trim();
}

// API base e token vêm mastigados do frontend
const apiBase = input.api_base || 'https://graph.instagram.com';
const accessToken = input.access_token || '';
const igAccountId = input.ig_account_id || '';
const videoUrl = input.metadata?.video_url || '';
const postId = input.id_post || '';
const authType = input.auth_type || 'instagram_direct';

if (!accessToken || !igAccountId || !videoUrl) {
  throw new Error(`Dados incompletos: token=${!!accessToken}, igId=${!!igAccountId}, video=${!!videoUrl}`);
}

console.log(`[Publish] ${authType} | API: ${apiBase} | IG: ${igAccountId}`);
console.log(`[Publish] Video: ${videoUrl.substring(0, 80)}...`);
console.log(`[Publish] Caption: ${caption.substring(0, 60)}...`);

return [{
  json: {
    apiBase,
    accessToken,
    igAccountId,
    videoUrl,
    caption,
    postId,
    authType,
    containerUrl: `${apiBase}/v21.0/${igAccountId}/media`,
    publishUrl: `${apiBase}/v21.0/${igAccountId}/media_publish`
  }
}];

// Extrair creation_id e preparar para polling
const prevData = $('Preparar Dados').first().json;
const container = $input.first().json;

const creationId = container.id;
if (!creationId) {
  throw new Error('Container não retornou creation_id: ' + JSON.stringify(container));
}

console.log(`[Publish] Container criado: ${creationId}`);

return [{
  json: {
    ...prevData,
    creationId,
    statusCheckUrl: `${prevData.apiBase}/v21.0/${creationId}?fields=status_code&access_token=${prevData.accessToken}`,
    attempts: 0,
    maxAttempts: 30
  }
}];

// Verificar se o container está pronto
const prevData = $('Extrair Container ID').first().json;
const status = $input.first().json;

const statusCode = status.status_code || status.status;
const attempts = (prevData.attempts || 0) + 1;

console.log(`[Publish] Status check #${attempts}: ${statusCode}`);

if (statusCode === 'FINISHED') {
  return [{
    json: {
      ...prevData,
      ready: true,
      statusCode
    }
  }];
}

if (statusCode === 'ERROR' || statusCode === 'EXPIRED') {
  throw new Error(`Container falhou com status: ${statusCode}`);
}

if (attempts >= prevData.maxAttempts) {
  throw new Error(`Timeout: status ainda ${statusCode} após ${attempts} tentativas`);
}

// Não está pronto, retornar para polling
return [{
  json: {
    ...prevData,
    ready: false,
    statusCode,
    attempts
  }
}];

// Resultado final
const prevData = $('Avaliar Status').first().json;
const publishResult = $input.first().json;

const mediaId = publishResult.id;

if (!mediaId) {
  console.error('[Publish] Erro na publicação:', JSON.stringify(publishResult));
  throw new Error('Publicação falhou: ' + (publishResult.error?.message || JSON.stringify(publishResult)));
}

console.log(`[Publish] ✅ Publicado com sucesso! Media ID: ${mediaId}`);

return [{
  json: {
    success: true,
    mediaId,
    postId: prevData.postId,
    igAccountId: prevData.igAccountId,
    authType: prevData.authType,
    message: `Post publicado com sucesso no Instagram (${prevData.authType})`
  }
}];
